def gen(rng, size):
    n = max(2, min(size, 100000))
    edges = [[rng.randint(0, i - 1), i] for i in range(1, n)]
    start = [rng.randint(0, 1) for _ in range(n)]
    target = start[:]
    for a, b in edges:
        if rng.random() < 0.3:
            target[a] ^= 1
            target[b] ^= 1
    return [n, edges, ''.join(str(c) for c in start), ''.join(str(c) for c in target)]

