var minimumFlips = function(n, edges, start, target) {
    const color = new Array(n);
    const tgt = new Array(n);
    for (let i = 0; i < n; i++) {
        color[i] = start.charCodeAt(i) - 48;
        tgt[i] = target.charCodeAt(i) - 48;
    }
    const adj = Array.from({ length: n }, () => []);
    for (let idx = 0; idx < edges.length; idx++) {
        const [u, v] = edges[idx];
        adj[u].push([v, idx]);
        adj[v].push([u, idx]);
    }
    const parent = new Array(n).fill(-1);
    const parentEdge = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const order = [0];
    let head = 0;
    while (head < order.length) {
        const u = order[head++];
        for (const [v, idx] of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                parentEdge[v] = idx;
                order.push(v);
            }
        }
    }
    const result = [];
    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        if (u === 0) continue;
        if (color[u] !== tgt[u]) {
            result.push(parentEdge[u]);
            color[u] ^= 1;
            color[parent[u]] ^= 1;
        }
    }
    if (color[0] !== tgt[0]) return [-1];
    result.sort((a, b) => a - b);
    return result;
};
